import{_ as r,o as a,c as d,a2 as e}from"./chunks/framework.ZhLefgN8.js";const g=JSON.parse('{"title":"活动资格说明","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/eligibility.md","filePath":"zh-CN/rewards/eligibility.md"}'),i={name:"rewards/eligibility.md"};function o(l,t,s,n,h,p){return a(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="活动资格说明" tabindex="-1">活动资格说明 <a class="header-anchor" href="#活动资格说明" aria-label="Permalink to &quot;活动资格说明&quot;">​</a></h1><p>LongBridge 平台活动并非对所有用户统一开放，每个活动都有明确的参与资格范围。系统通过用户分群（Segment）机制确定哪些账户可以参与，不在资格范围内的用户即使完成任务也不会获得奖励。</p><h2 id="资格判断维度" tabindex="-1">资格判断维度 <a class="header-anchor" href="#资格判断维度" aria-label="Permalink to &quot;资格判断维度&quot;">​</a></h2><p>活动资格通常基于以下一个或多个维度组合判断：</p><table tabindex="0"><thead><tr><th>维度</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>账户归属地</td><td>账户注册/开户所在地区</td><td>仅限香港账户 / 仅限新加坡账户</td></tr><tr><td>持牌人</td><td>账户归属的监管主体</td><td>仅限长桥证券</td></tr><tr><td>用户生命周期</td><td>用户在平台的阶段</td><td>新用户（注册 30 天内）/ 老用户 / 沉默用户</td></tr><tr><td>账户状态</td><td>KYC 完成情况、账户是否开通</td><td>已完成实名认证 / 已开通港股账户</td></tr><tr><td>渠道来源</td><td>注册时的流量来源</td><td>通过指定邀请链接注册 / 通过特定渠道注册</td></tr><tr><td>资产规模</td><td>账户资产金额档位</td><td>账户总资产超过指定金额</td></tr><tr><td>交易历史</td><td>是否有过交易记录</td><td>历史上从未交易 / 30 天内有交易</td></tr><tr><td>持仓情况</td><td>是否持有特定产品</td><td>当前持有港股仓位</td></tr><tr><td>白名单</td><td>运营手动圈定的特定用户列表</td><td>活动专属邀请用户</td></tr><tr><td>黑名单</td><td>被明确排除的用户（如违规账户）</td><td>已被标记异常的账户</td></tr></tbody></table><h2 id="新用户-vs-老用户的判定" tabindex="-1">新用户 vs 老用户的判定 <a class="header-anchor" href="#新用户-vs-老用户的判定" aria-label="Permalink to &quot;新用户 vs 老用户的判定&quot;">​</a></h2><p>「新用户」和「老用户」是最常见的分群维度，但各活动定义可能不同：</p><ul><li><strong>注册时间</strong>：在指定日期后完成注册，通常 30 天或 90 天内算新用户</li><li><strong>首次入金</strong>：账户历史上从未入金，或在活动期间内首次入金</li><li><strong>首次开户</strong>：完成 KYC 认证的时间在活动期限内</li><li><strong>综合判断</strong>：注册时间 + 从未入金 + 从未交易，三个条件同时满足</li></ul><blockquote><p>具体活动的&quot;新用户&quot;定义以活动详情页为准，参与前务必确认自己符合定义。</p></blockquote><h2 id="参与资格的常见限制" tabindex="-1">参与资格的常见限制 <a class="header-anchor" href="#参与资格的常见限制" aria-label="Permalink to &quot;参与资格的常见限制&quot;">​</a></h2><p><strong>单次参与限制</strong>：大部分活动同一账户只能参与一次，同一用户注册多个账号不能重复获得奖励，平台通过手机号、身份证等进行关联识别。</p><p><strong>账户类型限制</strong>：部分卡券奖励（如现金卡、碎股卡）只能由长桥证券（LB）账户使用。</p><p><strong>地区限制</strong>：活动对应的监管区域限制，例如仅适用于香港居民开设的港股账户，不适用于海外账户。</p><p><strong>先到先得名额限制</strong>：部分活动设有总名额上限，达到名额后即使符合条件也无法参与。</p><h2 id="如何确认自己的参与资格" tabindex="-1">如何确认自己的参与资格 <a class="header-anchor" href="#如何确认自己的参与资格" aria-label="Permalink to &quot;如何确认自己的参与资格&quot;">​</a></h2><ol><li>进入活动详情页，查看「参与条件」或「活动规则」部分</li><li>确认自己的账户类型、注册时间、KYC 状态是否符合</li><li>如活动页面未明确显示，可联系客服确认自己的账户是否在活动覆盖范围内</li><li>注意：活动页面能看到不代表有资格参与，显示活动内容是为了让用户了解活动，实际资格以后台配置为准</li></ol><h2 id="资格判定与异议处理答疑" tabindex="-1">资格判定与异议处理答疑 <a class="header-anchor" href="#资格判定与异议处理答疑" aria-label="Permalink to &quot;资格判定与异议处理答疑&quot;">​</a></h2><p><strong>Q：活动页面我能看到，完成了任务但没有奖励，为什么？</strong></p><p>A：能看到活动页面不代表有参与资格。活动资格由后台用户分群决定，若您的账户不在该活动的目标用户范围内（如活动仅针对新用户、特定渠道注册用户等），即使完成任务也不会触发奖励。建议在参与前联系客服确认资格，或仔细阅读活动规则中的「参与条件」。</p><p><strong>Q：我重新注册了一个账号，可以再次参与新用户活动吗？</strong></p><p>A：不可以。平台通过手机号、身份证号等信息关联同一自然人的多个账号，同一用户重复注册参与活动属于违规行为。被检测到后，奖励可能被取消，账户可能被处理。</p><p><strong>Q：同样是新用户，为什么我的朋友有奖励而我没有？</strong></p><p>A：可能原因：（1）您的朋友通过特定渠道（如邀请链接）注册，参与了定向活动，您未通过该渠道；（2）活动有地区或账户类型限制；（3）活动名额已满。建议对比活动的具体参与条件。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards/奖励系统概览">奖励系统概览</a> — 奖励分配机制</li><li><a href="/wiki/rewards/开户礼包与激活奖励">开户礼包与激活奖励</a> — 新用户活动</li></ul>',25)])])}const u=r(i,[["render",o]]);export{g as __pageData,u as default};
